/* adm-item-itemgroup-sql-oracle.xml - selectItemGroupCode */
SELECT 	ICGRPNM
	   ,ICGRPKEY
FROM 	TADMIN_MST_ICGR
WHERE   OWKEY = #{owkey}

/* adm-item-itemgroup-sql-oracle.xml - selectItemGroup */ #{GRIDPAGING_ROWNUMTYPE_TOP} SELECT'0' AS CHK , OWKEY , (SELECT OWNM FROM TADMIN_MST_OW OW WHERE OW.OWKEY = TADMIN_MST_ICGR.OWKEY) AS OWNM , UPDATEDATE , INSERTDATE , INSERTURKEY , UPDATEURKEY , ICGRPTYPE , ICGRPNM , ICGRPKEY , CLOSDATE , SAMFILENM , IFYN FROM TADMIN_MST_ICGR
#{SEARCH_CONDITION}
ORDER BY #{colName} DESC
ORDER BY #{colName} ASC
ORDER BY UPDATEDATE DESC
#{GRIDPAGING_ROWNUMTYPE_BOTTOM}

		/* adm-item-itemgroup-sql-oracle.xml - selectItemGroupCount */
		SELECT 	COUNT(1)  
  		FROM 	TADMIN_MST_ICGR 


		   		#{SEARCH_CONDITION}

		/* adm-item-itemgroup-sql-oracle.xml - selectCountTAdminMstIcgrXCt */
		SELECT 	COUNT(1)  
  		FROM 	TADMIN_MST_ICGRXCT
	    WHERE	CTKEY = #{ctkey}
	    AND     OWKEY = #{owkey}
	    AND     ICGRPKEY = #{icgrpkey}
	    AND     ICGRPTYPE = #{icgrptype}

mapper.insert:
/* adm-item-itemgroup-sql-oracle.xml - insertTAdminMstIcgr */
INSERT INTO TADMIN_MST_ICGR	(
	UPDATEURKEY
	,UPDATEDATE
	,INSERTURKEY
	,INSERTDATE
	,ICGRPTYPE
	,ICGRPNM
	,ICGRPKEY
	,CLOSDATE
	,OWKEY
	,SAMFILENM
)
VALUES (
	#{surkey}
	,#{sysdate}
	,#{surkey}
	,#{sysdate}
	,#{icgrptype}
	,#{icgrpnm}
	,#{icgrpkey}
	,SUBSTR(#{closdate}, 0, 14)
	,#{owkey}
	,#{samfilenm}
)

mapper.update:
		/* adm-item-itemgroup-sql-oracle.xml - updateTAdminMstIcgr */
		UPDATE 	TADMIN_MST_ICGR 
		SET		UPDATEURKEY = #{surkey}
				,UPDATEDATE  = #{sysdate}
				,ICGRPNM    = #{icgrpnm}
				,SAMFILENM = #{samfilenm}
				,CLOSDATE = SUBSTR(#{closdate}, 0, 14)
	    WHERE 	OWKEY = #{owkey}
    	AND 	ICGRPKEY = #{icgrpkey}
        AND 	ICGRPTYPE = #{icgrptype}

mapper.insert:
/* adm-item-itemgroup-sql-oracle.xml - insertTAdminMstIcgrxct */
/* Converted from: MERGE INTO TADMIN_MST_ICGRXCT ON CONFLICT */
INSERT INTO TADMIN_MST_ICGRXCT (
		 UPDATEURKEY, UPDATEDATE, INSERTURKEY, INSERTDATE
		,ICGRPTYPE, ICGRPKEY, CTKEY, OWKEY
	) VALUES (
		 #{surkey}, #{sysdate}, #{surkey}, #{sysdate}
		,#{icgrptype}, #{icgrpkey}, #{ctkey}, #{owkey}
	)
ON CONFLICT (OWKEY, ICGRPKEY, ICGRPTYPE, CTKEY) DO UPDATE SET
		 UPDATEURKEY = #{surkey}
		,UPDATEDATE = #{sysdate}

mapper.delete:
		/* adm-item-itemgroup-sql-oracle.xml - deleteTAdminMstIcgrxct */
		DELETE
	  	FROM 	TADMIN_MST_ICGRXCT	
     	WHERE 	OWKEY = #{owkey}
     	AND		ICGRPKEY = #{icgrpkey}
        AND 	ICGRPTYPE = #{icgrptype}

			AND CTKEY = #{ctkey}

		/* adm-item-itemgroup-sql-oracle.xml - deleteTAdminMstIcgr */
		DELETE
		FROM 	TADMIN_MST_ICGR	
 	    WHERE 	OWKEY = #{owkey}
	    AND  	ICGRPKEY = #{icgrpkey}
        AND 	ICGRPTYPE = #{icgrptype}
